pair A, B, M;

A = (-11,3);
B = (3,-7);
M = (A + B)/2;

draw(A--B);

dot("$-11 + 3i$", A ,NW);
dot("$3 - 7i$", B, SE);
dot("$-4 - 2i$", M, NE);
[/asy]

